def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 21):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.2
            elif j % 2 == 0:
                term *= 0.85
            else:
                term *= 0.95
            score += term
        if capacity < item * 1.1:
            score *= 1.7
            for k in range(1, 5):
                increment = ((item / (capacity + k)) ** 2) * 0.04
                score += increment
        elif capacity < item * 2.5:
            score *= 1.2
            for k in range(1, 4):
                if (capacity / k) > item * 0.8:
                    score += 0.03 * k
                else:
                    score -= 0.02 * k
        elif capacity > item * 5:
            score *= 0.6
            for k in range(1, 5):
                penalty = (capacity / (item * k)) * 0.05
                score -= penalty
        else:
            for k in range(1, 7):
                if (capacity / k) > item * 1.1:
                    score += 0.025 * k
                else:
                    score -= 0.015 * k
        if i % 4 == 0:
            score *= 1.07
            for m in range(1, 3):
                score += (np.sin(i * m) * 0.01)
        elif i % 6 == 0:
            score *= 0.93
            for m in range(1, 4):
                score -= (np.cos(i * m) * 0.02)
        if capacity % 3 == 0:
            score *= 1.03
        elif capacity % 5 == 0:
            score *= 0.97
        if score < 0.05:
            score += 0.07
        if np.isclose(score, 0):
            score = 0.1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 20
    return priorities
